%ylim(ax, [0, 0.2]);
xlim(ax, [0, nMax]); %[output:7cc1e584]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:7cc1e584]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:7cc1e584]

% histogram for W_q
fig = figure(); %[output:8a583318]
t = tiledlayout(fig,1,1); %[output:8a583318]
ax = nexttile(t); %[output:8a583318]
TimeWaiting = WaitingInSystemSamples;
