ylabel(ax, "Probability"); %[output:8a583318]
pause(2);
exportgraphics(fig, PictureFolder + filesep + "Wq_histogram.pdf"); %[output:8a583318]
ServiceTimes = cellfun(@(q) cellfun(@(c) c.DepartureTime - c.BeginServiceTime, q.Served'), QSamples, UniformOutput=false);
ServiceTimes = vertcat(ServiceTimes{:});
CustomersServed = cellfun(@(q) length(q.Served), QSamples);
%histogram for service times
fig = figure(); %[output:4dc5fbfa]
t = tiledlayout(fig,1,1); %[output:4dc5fbfa]
ax = nexttile(t); %[output:4dc5fbfa]
h = histogram(ax, ServiceTimes, Normalization = "probability", BinWidth = 5/60); %[output:4dc5fbfa]
